<?php
session_start(); include "includes/db.php"; include "includes/model.php"; requireLogin(); requirePermission("can_add_stock"); $msg="";
if($_SERVER["REQUEST_METHOD"]=="POST"){ $n=mysqli_real_escape_string($conn,$_POST["product_name"]);$c=mysqli_real_escape_string($conn,$_POST["category"]);$l=mysqli_real_escape_string($conn,$_POST["location"]);$s=mysqli_real_escape_string($conn,$_POST["supplier"]);$b=mysqli_real_escape_string($conn,$_POST["batch_no"]); $stock=intval($_POST["current_stock"]);$base=intval($_POST["base_daily_sales"]);$expiry=intval($_POST["days_to_expiry"]);$price=floatval($_POST["unit_price"]);$promo=isset($_POST["promotion_flag"])?1:0; mysqli_query($conn,"INSERT INTO products(store_id,product_name,category,location,supplier,batch_no,current_stock,base_daily_sales,days_to_expiry,unit_price,promotion_flag) VALUES(1,'$n','$c','$l','$s','$b',$stock,$base,$expiry,$price,$promo)"); $msg="Stock added successfully and connected to FreshGuard forecasting model."; }
?><!DOCTYPE html><html><head><title>Add Stock</title><link rel="stylesheet" href="assets/style.css"></head><body><div class="layout"><?php include "includes/sidebar.php"; ?><main class="main"><div class="page-title"><h1>Add Stock</h1><p>Add product batch for FreshGuard Supermarket</p></div><div class="card"><?php if($msg) echo "<p style='color:green'>$msg</p><br>"; ?><form method="POST" class="form-grid"><input name="product_name" placeholder="Product Name" required><input name="category" placeholder="Category" required><input name="location" placeholder="Store Location" required><input name="supplier" placeholder="Supplier"><input name="batch_no" placeholder="Batch Number"><input type="number" name="current_stock" placeholder="Current Stock" required><input type="number" name="base_daily_sales" placeholder="Base Daily Sales" required><input type="number" name="days_to_expiry" placeholder="Days to Expiry" required><input type="number" step="0.01" name="unit_price" placeholder="Unit Price" required><label><input type="checkbox" name="promotion_flag" style="width:auto"> Promotion Active</label><button>Add Stock</button></form></div></main></div></body></html>